"use client";

import { useRef, useEffect, useState } from 'react';
import { useSprings, animated } from '@react-spring/web';

export default function BlurText({
  text = '',
  delay = 200,
  className = '',
  animateBy = 'words', // 'words' or 'letters'
  onAnimationComplete,
}) {
  const elements = animateBy === 'words' ? text.split(' ') : text.split('');
  const [state, setState] = useState(false);
  const ref = useRef(null);

  useEffect(() => {
    const timer = setTimeout(() => {
      setState(true);
    }, 0);
    return () => clearTimeout(timer);
  }, []);

  const springs = useSprings(
    elements.length,
    elements.map((_, i) => ({
      from: { filter: 'blur(10px)', opacity: 0, transform: 'translate3d(0,5px,0)' },
      to: async (next) => {
        if (state) {
          await next({ filter: 'blur(0px)', opacity: 1, transform: 'translate3d(0,0px,0)', delay: i * delay });
        }
      },
      config: { tension: 200, friction: 20 },
    }))
  );

  return (
    <p ref={ref} className={`flex flex-wrap ${className}`}>
      {springs.map((props, index) => (
        <animated.span
          key={index}
          style={props}
          className="inline-block will-change-[transform,opacity,filter] mr-[0.2em]"
        >
          {elements[index] === ' ' ? '\u00A0' : elements[index]}
        </animated.span>
      ))}
    </p>
  );
}